// Formater la liste des services
const response = $input.item.json.result || $input.item.json;
const services = response.data || response.services || [];

if (services.length === 0) {
  return {
    json: {
      success: true,
      message: "Aucun service BunkerWeb configuré.",
      services: []
    }
  };
}

let formattedText = `Services BunkerWeb configurés (${services.length}) :\n\n`;

services.forEach((svc, idx) => {
  const status = svc.is_draft ? '📝 Brouillon' : '✅ En ligne';
  const serviceName = svc.id || svc.SERVER_NAME || 'Unknown';
  formattedText += `${idx + 1}. **${serviceName}** - ${status}\n`;
  formattedText += `   • Méthode: ${svc.method || 'N/A'}\n`;

  if (svc.creation_date) {
    const date = new Date(svc.creation_date).toLocaleString('fr-FR');
    formattedText += `   • Créé le: ${date}\n`;
  }

  // Afficher quelques variables importantes si disponibles
  if (svc.USE_MODSECURITY) {
    formattedText += `   • ModSecurity: ${svc.USE_MODSECURITY}\n`;
  }
  if (svc.USE_ANTIBOT) {
    formattedText += `   • Antibot: ${svc.USE_ANTIBOT}\n`;
  }
  formattedText += '\n';
});

return {
  json: {
    success: true,
    message: formattedText,
    services: services,
    count: services.length
  }
};
